SELECT #{item.batchAppId, jdbcType=VARCHAR} AS BATCH_APP_ID, #{item.instanceId, jdbcType=VARCHAR} AS INSTANCE_ID, #{item.batchDate, jdbcType=VARCHAR} AS BATCH_DATE, #{item.batchExecuteSeq, jdbcType=INTEGER} AS BATCH_EXECUTE_SEQ, #{item.logDtime, jdbcType=VARCHAR} AS LOG_DTIME, #{item.resRtCode, jdbcType=VARCHAR} AS RES_RT_CODE, #{item.lastUpdateUserId, jdbcType=VARCHAR} AS LAST_UPDATE_USER_ID FROM DUAL
) A

